var orderStatusSchema = external_exports.enum(["pending", "confirmed", "in_transit", "delivered", "cancelled"]);
var notificationChannelSchema = external_exports.enum(["email", "sms", "whatsapp"]);
async function updateOrderStatusInternal(input) {
  const database = await getDb();
  if (!database) throw new Error("Database not available");
  await database.update(orders).set({
    status: input.status,
    updatedAt: /* @__PURE__ */ new Date()
  }).where(eq(orders.id, input.orderId));
  const updatedOrders = await database.select().from(orders).where(eq(orders.id, input.orderId)).limit(1);
  if (!updatedOrders || updatedOrders.length === 0) {
    throw new Error("Failed to update order status");
  }
  const order = updatedOrders[0];
  const statusLabels = {
    pending: "En Attente",
    confirmed: "Confirm\xE9e",
    in_transit: "En Cours de Livraison",
    delivered: "Livr\xE9e",
    cancelled: "Annul\xE9e"
  };
  const statusLabel = statusLabels[input.status];
  if (input.notificationChannel === "email" && order.customerEmail) {
    await sendStatusUpdateEmail({
      orderNumber: order.orderNumber,
      customerName: order.customerName,
      customerEmail: order.customerEmail,
      status: input.status,
      statusLabel,
      estimatedDeliveryDate: input.estimatedDeliveryDate,
      courierName: input.courierName,
      courierPhone: input.courierPhone
    });
  } else if (input.notificationChannel === "sms") {
    const smsMessage = `Bonjour ${order.customerName}, votre commande ${order.orderNumber} est ${statusLabel.toLowerCase()}. Merci de votre confiance!`;
    if (order.customerPhone) {
      await sendSMS(order.customerPhone, smsMessage, order.id, input.status);
    }
  } else if (input.notificationChannel === "whatsapp") {
    const whatsappMessage = `Bonjour ${order.customerName},

Votre commande ${order.orderNumber} est maintenant ${statusLabel.toLowerCase()}.

${input.courierName ? `Livreur: ${input.courierName}` : ""}
${input.courierPhone ? `T\xE9l\xE9phone: ${input.courierPhone}` : ""}
${input.estimatedDeliveryDate ? `Livraison estim\xE9e: ${input.estimatedDeliveryDate}` : ""}

Merci de votre confiance!`;
    console.log("[WhatsApp] Message to send:", {
      to: order.customerPhone,
      message: whatsappMessage
    });
  }
  return {
    success: true,
    order: {
      id: order.id,
      orderNumber: order.orderNumber,
      status: order.status,
      updatedAt: order.updatedAt
    }
  };
}
