var assertApiKey = () => {
  if (!ENV.anthropicApiKey) {
    throw new Error("ANTHROPIC_API_KEY is not configured");
  }
};
var contentToText = (content) => {
  const parts = Array.isArray(content) ? content : [content];
  return parts.map((part) => typeof part === "string" ? part : part.text).join("\n");
};
async function invokeLLM(params) {
  assertApiKey();
  const systemMessages = params.messages.filter((m2) => m2.role === "system");
  const conversationMessages = params.messages.filter((m2) => m2.role !== "system");
  const system = systemMessages.map((m2) => contentToText(m2.content)).join("\n\n") || void 0;
  const messages2 = conversationMessages.map((m2) => ({
    role: m2.role === "assistant" ? "assistant" : "user",
    content: contentToText(m2.content)
  }));
  const response = await fetch(ANTHROPIC_API_URL, {
    method: "POST",
    headers: {
      "content-type": "application/json",
      "x-api-key": ENV.anthropicApiKey,
      "anthropic-version": "2023-06-01"
    },
    body: JSON.stringify({
      model: DEFAULT_MODEL,
      max_tokens: params.max_tokens ?? params.maxTokens ?? 1024,
      system,
      messages: messages2
    })
  });
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(
      `LLM invoke failed: ${response.status} ${response.statusText} \u2013 ${errorText}`
    );
  }
  const data = await response.json();
  const text2 = (data.content ?? []).filter((b) => b.type === "text").map((b) => b.text).join("\n");
  return {
    id: data.id,
    model: data.model,
    choices: [
      {
        index: 0,
        message: { role: "assistant", content: text2 },
        finish_reason: data.stop_reason ?? null
      }
    ],
    usage: data.usage ? {
      prompt_tokens: data.usage.input_tokens,
      completion_tokens: data.usage.output_tokens,
      total_tokens: data.usage.input_tokens + data.usage.output_tokens
    } : void 0
  };
}

// server/ai-chat-router.ts
var aiChatRouter = router({
  /**
   * Send a message to the AI chatbot
   * The AI will respond based on the conversation context
   */
  sendMessage: protectedProcedure.input(
    external_exports.object({
      conversationId: external_exports.string().optional(),
      message: external_exports.string().min(1).max(5e3),
      context: external_exports.object({
        userType: external_exports.enum(["customer", "vendor", "admin"]).optional(),
        productId: external_exports.number().optional(),
        orderId: external_exports.number().optional()
      }).optional()
    })
  ).mutation(async ({ ctx, input }) => {
    try {
      let systemPrompt = `You are a helpful customer support AI for Cavaly Livres, an e-commerce platform selling school and university textbooks, literary works, stationery, and writing supplies in C\xF4te d'Ivoire.

You should:
- Be friendly, professional, and helpful
- Respond in French (the user's language)
- Provide accurate information about products and services
- Help with order tracking and delivery information
- Answer questions about payment methods (Wave, Orange Money, card)
- Assist with product recommendations
- Escalate to human support if the issue is complex or urgent

Current user type: ${input.context?.userType || "customer"}`;
      if (input.context?.productId) {
        systemPrompt += `
The user is asking about a specific product (ID: ${input.context.productId}).`;
      }
      if (input.context?.orderId) {
        systemPrompt += `
The user is asking about a specific order (ID: ${input.context.orderId}).`;
      }
      const conversationHistory = [];
      if (input.conversationId) {
      }
      conversationHistory.push({
        role: "user",
        content: input.message
      });
      const response = await invokeLLM({
        messages: [
          { role: "system", content: systemPrompt },
          ...conversationHistory.map((msg) => ({
            role: msg.role,
            content: msg.content
          }))
        ]
      });
      const aiResponse = response.choices[0]?.message?.content || "Je suis d\xE9sol\xE9, je n'ai pas pu traiter votre demande.";
      return {
        success: true,
        message: aiResponse,
        conversationId: input.conversationId || `conv_${Date.now()}`
      };
    } catch (error51) {
      console.error("AI Chat Error:", error51);
      return {
        success: false,
        message: "Une erreur s'est produite. Veuillez r\xE9essayer ou contacter le support.",
        conversationId: input.conversationId
      };
    }
  }),
  /**
   * Get AI chat suggestions for common questions
   */
  getSuggestions: protectedProcedure.input(
    external_exports.object({
      userType: external_exports.enum(["customer", "vendor", "admin"]).optional()
    })
  ).query(async ({ input }) => {
    const suggestions = {
      customer: [
        "Comment puis-je suivre ma commande?",
        "Quels sont les d\xE9lais de livraison?",
        "Quels modes de paiement acceptez-vous?",
        "Comment puis-je retourner un produit?",
        "Avez-vous des livres sur un sujet sp\xE9cifique?"
      ],
      vendor: [
        "Comment ajouter mes produits?",
        "Comment g\xE9rer mes commandes?",
        "Comment communiquer avec les clients?",
        "Quels sont les frais de commission?",
        "Comment retirer mes gains?"
      ],
      admin: [
        "Voir les statistiques de vente",
        "G\xE9rer les utilisateurs",
        "Consulter les commandes",
        "Voir les rapports",
        "G\xE9rer les cat\xE9gories de produits"
      ]
    };
    return suggestions[input.userType || "customer"] || suggestions.customer;
  }),
  /**
   * Escalate to human support
   */
  escalateToHuman: protectedProcedure.input(
    external_exports.object({
      conversationId: external_exports.string(),
      reason: external_exports.string().min(1).max(500),
      priority: external_exports.enum(["low", "medium", "high"]).default("medium")
    })
  ).mutation(async ({ ctx, input }) => {
    try {
      return {
        success: true,
        message: "Votre demande a \xE9t\xE9 transmise \xE0 notre \xE9quipe de support. Un agent vous contactera bient\xF4t.",
        ticketId: `TICKET_${Date.now()}`
      };
    } catch (error51) {
      console.error("Escalation Error:", error51);
      return {
        success: false,
        message: "Une erreur s'est produite lors de l'escalade."
      };
    }
  })
});

